/* Ã¢â€â‚¬Ã¢â€â‚¬ FADE-IN HOOK Ã¢â€â‚¬Ã¢â€â‚¬ */
function useFadeIn() {
  const ref = useRef(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { el.classList.add('visible'); obs.disconnect(); } },
      { threshold: 0.08 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);
  return ref;
}

function FadeIn({ children, className = '' }) {
  const ref = useFadeIn();
  return <div ref={ref} className={`fade-item ${className}`}>{children}</div>;
}

/* Ã¢â€â‚¬Ã¢â€â‚¬ TYPING EFFECT Ã¢â€â‚¬Ã¢â€â‚¬ */
const TYPING_PHRASES = [
  'AI Engineer',
  'Computer Vision',
  'NLP Researcher',
  'Multi-Agent Systems',
  'Deep Learning',
  'Agentic AI',
];

function TypingEffect() {
  const [displayed, setDisplayed] = useState('');
  const [phraseIdx, setPhraseIdx] = useState(0);
  const [charIdx, setCharIdx] = useState(0);
  const [deleting, setDeleting] = useState(false);
  const [blink, setBlink] = useState(true);

  useEffect(() => {
    const blinkTimer = setInterval(() => setBlink(b => !b), 530);
    return () => clearInterval(blinkTimer);
  }, []);

  useEffect(() => {
    const phrase = TYPING_PHRASES[phraseIdx];
    let delay = deleting ? 60 : 100;
    if (!deleting && charIdx === phrase.length) delay = 1600;
    if (deleting && charIdx === 0) delay = 400;

    const timer = setTimeout(() => {
      if (!deleting && charIdx < phrase.length) {
        setDisplayed(phrase.slice(0, charIdx + 1));
        setCharIdx(c => c + 1);
      } else if (!deleting && charIdx === phrase.length) {
        setDeleting(true);
      } else if (deleting && charIdx > 0) {
        setDisplayed(phrase.slice(0, charIdx - 1));
        setCharIdx(c => c - 1);
      } else if (deleting && charIdx === 0) {
        setDeleting(false);
        setPhraseIdx(i => (i + 1) % TYPING_PHRASES.length);
      }
    }, delay);
    return () => clearTimeout(timer);
  }, [charIdx, deleting, phraseIdx]);

  return (
    <div className="typing-box">
      <div className="typing-label">Currently working on</div>
      <div className="typing-text">
        {displayed}
        <span className="typing-cursor" style={{ opacity: blink ? 1 : 0 }}>|</span>
      </div>
      <div className="typing-tags">
        {TYPING_PHRASES.map((p, i) => (
          <span key={i} className={`typing-tag ${i === phraseIdx ? 'active' : ''}`}>{p}</span>
        ))}
      </div>
      <div className="typing-location">Ã°Å¸â€œÂ Riyadh, Saudi Arabia</div>
    </div>
  );
}

